import{_ as o,c as t,o as a,ag as r}from"./chunks/framework.Bw-5EFTY.js";const p=JSON.parse('{"title":"DAG Projection Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-projection/SPEC.md","filePath":"packages/dag-projection/SPEC.md"}'),i={name:"packages/dag-projection/SPEC.md"};function n(c,e,d,s,l,u){return a(),t("div",null,e[0]||(e[0]=[r('<h1 id="dag-projection-specification" tabindex="-1">DAG Projection Specification <a class="header-anchor" href="#dag-projection-specification" aria-label="Permalink to &quot;DAG Projection Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Builds query/read models for DAG runs and tasks from storage records. Provides run projections (status summaries), lineage projections (graph structure with task status overlay), and combined dashboard projections. All projection updates are deterministic from explicit fields -- no derived heuristics.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Depends on <code>dag-core</code> for domain contracts (<code>IDagRun</code>, <code>ITaskRun</code>, <code>IDagDefinition</code>, <code>IStoragePort</code>), error builders, and status types.</li><li>No dispatch, worker, or scheduling behavior in this package.</li><li>Does not mutate run or task state -- read-only projections.</li><li>Does not own API response shaping -- that belongs to <code>dag-api</code>.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Single-service architecture:</p><ul><li><strong>ProjectionReadModelService</strong> (<code>services/projection-read-model-service.ts</code>): Accepts <code>IStoragePort</code> via constructor. Provides three projection builders: <ol><li><code>buildRunProjection(dagRunId)</code> -- fetches <code>IDagRun</code> and its <code>ITaskRun[]</code>, computes a <code>TTaskStatusSummary</code> counting tasks by status.</li><li><code>buildLineageProjection(dagRunId)</code> -- builds on top of run projection, fetches the definition, maps nodes and edges with optional task status overlay.</li><li><code>buildDashboardProjection(dagRunId)</code> -- combines run and lineage projections into a single response.</li></ol></li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>TTaskStatusSummary</code> -- counts per task status (created, queued, running, success, failed, upstream_failed, skipped, cancelled)</li><li><code>IRunProjection</code> -- run projection (dagRun, taskRuns, taskStatusSummary)</li><li><code>ILineageNodeProjection</code> -- lineage node (nodeId, nodeType, dependsOn, taskStatus?)</li><li><code>ILineageEdgeProjection</code> -- lineage edge (from, to)</li><li><code>ILineageProjection</code> -- lineage projection (dagId, version, dagRunId, nodes, edges)</li><li><code>IDashboardProjection</code> -- combined run + lineage projection</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>ProjectionReadModelService</code> -- main service class <ul><li><code>constructor(storage: IStoragePort)</code></li><li><code>buildRunProjection(dagRunId): Promise&lt;TResult&lt;IRunProjection, IDagError&gt;&gt;</code></li><li><code>buildLineageProjection(dagRunId): Promise&lt;TResult&lt;ILineageProjection, IDagError&gt;&gt;</code></li><li><code>buildDashboardProjection(dagRunId): Promise&lt;TResult&lt;IDashboardProjection, IDagError&gt;&gt;</code></li></ul></li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li>Accepts <code>IStoragePort</code> from <code>dag-core</code> via constructor injection. Custom storage implementations provide the underlying data.</li><li>No abstract classes to extend; the service is used directly.</li><li><code>dag-api</code>&#39;s <code>DagObservabilityController</code> consumes this service for API-layer projection queries.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors use <code>IDagError</code> from <code>dag-core</code> with <code>category: &#39;validation&#39;</code>:</p><ul><li><code>DAG_VALIDATION_DAG_RUN_NOT_FOUND</code> -- DAG run not found for the requested projection</li><li><code>DAG_VALIDATION_DEFINITION_NOT_FOUND</code> -- definition not found for lineage projection (required to map nodes and edges)</li></ul><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>None. <code>ProjectionReadModelService</code> does not use <code>implements</code>.</p><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Service class is standalone.</p><h3 id="port-consumption-via-di" tabindex="-1">Port Consumption via DI <a class="header-anchor" href="#port-consumption-via-di" aria-label="Permalink to &quot;Port Consumption via DI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service Class</th><th>Injected Port (from dag-core)</th><th>Location</th></tr></thead><tbody><tr><td><code>ProjectionReadModelService</code></td><td><code>IStoragePort</code></td><td><code>src/services/projection-read-model-service.ts</code></td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer Class</th><th>Location</th></tr></thead><tbody><tr><td><code>IStoragePort</code> (dag-core)</td><td><code>ProjectionReadModelService</code></td><td><code>src/services/projection-read-model-service.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: <code>projection-read-model-service.test.ts</code></li><li>Tests use in-memory port implementations from <code>dag-core</code>.</li><li>Coverage focus: run projection with status summary computation, lineage projection with node/edge mapping and task status overlay, dashboard composition, error paths for missing run and missing definition.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-projection test</code></li></ul>',29)]))}const g=o(i,[["render",n]]);export{p as __pageData,g as default};
